 26→// Types
 27→// ---------------------------------------------------------------------------
 28→
 29→type SupportedTable = "task" | "intent" | "git_commit" | "decision" | "observation";
 30→
 31→const SUPPORTED_TABLES = new Set<string>([
 32→  "task",
 33→  "intent",
 34→  "git_commit",
 35→  "decision",
