 84→// ---------------------------------------------------------------------------
 85→// Route handler factory
 86→// ---------------------------------------------------------------------------
 87→
 88→export function createObserverRouteHandler(deps: ServerDependencies) {
 89→  return async (table: string, id: string, request: Request): Promise<Response> => {
 90→    if (!SUPPORTED_TABLES.has(table)) {
 91→      return jsonResponse({ error: "unsupported_table", table }, 400);
 92→    }
 93→
 94→    const supportedTable = table as SupportedTable;
 95→
 96→    try {
 97→      // Parse the EVENT body (the record itself, posted by SurrealDB EVENT)
 98→      const body = await request.json().catch(() => undefined);
 99→
100→      logInfo("observer.event.received", "Observer event received", {
101→        table: supportedTable,
102→        id,
103→      });
104→
105→      // Dispatch to the appropriate verification pipeline
106→      switch (supportedTable) {
107→        case "task":
108→          await handleTaskVerification(deps, id, body);
109→          break;
110→
111→        case "intent":
