442→        await persistVerificationObservation(
443→          surreal, workspaceRecord, originalObservationRecord, reviewResult, "llm",
444→        );
445→
446→        logInfo("observer.observation.llm_peer_reviewed", "LLM peer review complete", {
447→          observationId,
448→          verdict: llmVerdict.verdict,
449→          confidence: llmVerdict.confidence,
450→        });
451→        return;
452→      }
453→      // LLM failed — fall through to deterministic
454→      logInfo("observer.llm.fallback", "LLM peer review failed, using deterministic", { observationId });
455→    } else {
456→      logInfo("observer.llm.skip", "LLM peer review skipped: no linked entities", { observationId });
457→    }
458→  }
459→
460→  // Deterministic fallback
461→  await persistVerificationObservation(surreal, workspaceRecord, originalObservationRecord, deterministicResult, "peer_review");
462→
463→  logInfo("observer.observation.peer_reviewed", "Observation peer review complete", {
464→    observationId,
465→    verdict: deterministicResult.verdict,
466→    severity: deterministicResult.severity,
467→  });
468→}
469→
470→async function gatherObservationPeerReviewSignals(
471→  surreal: Surreal,
472→  workspaceRecord: RecordId<"workspace", string>,
473→  body?: Record<string, unknown>,
474→): Promise<ObservationPeerReviewSignals> {
475→  const originalText = (body?.text as string) ?? "Unknown observation";
476→  const originalSeverity = ((body?.severity as string) ?? "info") as "info" | "warning" | "conflict";
477→  const sourceAgent = (body?.source_agent as string) ?? "unknown_agent";
478→
479→  // Count tasks and decisions in the workspace for cross-checking context
480→  const [taskRows] = await surreal.query<[Array<{ count: number }>]>(
481→    `SELECT count() AS count FROM task WHERE workspace = $ws GROUP ALL;`,
482→    { ws: workspaceRecord },
483→  );
484→
485→  const [decisionRows] = await surreal.query<[Array<{ count: number }>]>(
486→    `SELECT count() AS count FROM decision WHERE workspace = $ws GROUP ALL;`,
487→    { ws: workspaceRecord },
488→  );
489→
490→  return {
491→    originalText,
492→    originalSeverity,
493→    sourceAgent,
494→    relatedTaskCount: taskRows?.[0]?.count ?? 0,
495→    relatedDecisionCount: decisionRows?.[0]?.count ?? 0,
496→  };
497→}
498→
499→async function gatherDecisionSignals(
500→  surreal: Surreal,
501→  workspaceRecord: RecordId<"workspace", string>,
502→  body?: Record<string, unknown>,
503→): Promise<DecisionSignals> {
504→  const status = (body?.status as string) ?? "unknown";
505→  const summary = (body?.summary as string) ?? "Unknown decision";
506→
507→  // Count completed tasks in the workspace
508→  const [taskRows] = await surreal.query<[Array<{ count: number }>]>(
509→    `SELECT count() AS count FROM task WHERE workspace = $ws AND (status = "completed" OR status = "done") GROUP ALL;`,
510→    { ws: workspaceRecord },
511→  );
512→
513→  const completedTaskCount = taskRows?.[0]?.count ?? 0;
514→
515→  return { status, summary, completedTaskCount };
516→}
517→
518→// ---------------------------------------------------------------------------
519→// Graph scan route handler factory
520→// ---------------------------------------------------------------------------
521→
522→export function createGraphScanRouteHandler(deps: ServerDependencies) {
523→  return async (workspaceId: string, _request: Request): Promise<Response> => {
524→    try {
525→      logInfo("observer.scan.started", "Graph scan triggered", { workspaceId });
526→
527→      const workspaceRecord = new RecordId("workspace", workspaceId);
528→      const result = await runGraphScan(deps.surreal, workspaceRecord, deps.observerModel as LanguageModel | undefined);
529→
530→      return jsonResponse({
531→        status: "ok",
532→        ...result,
533→      }, 200);
534→    } catch (error) {
535→      logError("observer.scan.error", "Graph scan failed", error);
536→      return jsonResponse({ status: "error", message: "scan failed" }, 500);
537→    }
538→  };
539→}
540→
541→// ---------------------------------------------------------------------------
542→// Workspace resolution
543→// ---------------------------------------------------------------------------
544→
545→const UUID_PATTERN = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
546→
547→async function resolveWorkspaceId(
548→  surreal: Surreal,
549→  table: string,
550→  id: string,
551→  body?: Record<string, unknown>,
552→): Promise<string | undefined> {
553→  // Try body first (SurrealDB EVENT passes the full record)
554→  let wsId: string | undefined;
555→
556→  if (body?.workspace) {
557→    const ws = body.workspace;
558→    // Could be a RecordId-like object or a string
559→    if (typeof ws === "string") {
560→      // Handle "workspace:uuid" format and strip backticks
561→      const cleaned = ws.replace(/`/g, "");
562→      wsId = cleaned.includes(":") ? cleaned.split(":")[1] : cleaned;
563→    } else if (typeof ws === "object" && ws !== null) {
564→      const wsObj = ws as { id?: string | { String?: string } };
565→      if (typeof wsObj.id === "string") wsId = wsObj.id.replace(/`/g, "");
566→      else if (wsObj.id && typeof (wsObj.id as { String?: string }).String === "string") {
567→        wsId = (wsObj.id as { String: string }).String.replace(/`/g, "");
568→      }
569→    }
570→  }
571→
572→  // Fallback: query the DB
573→  if (!wsId) {
574→    const record = new RecordId(table, id);
575→    const [rows] = await surreal.query<
576→      [Array<{ workspace: RecordId<"workspace", string> }>]
577→    >(
578→      `SELECT workspace FROM $record;`,
579→      { record },
580→    );
581→
582→    const wsRecord = rows?.[0]?.workspace;
583→    wsId = wsRecord ? (wsRecord.id as string) : undefined;
584→  }
585→
586→  if (wsId && !UUID_PATTERN.test(wsId)) {
587→    throw new Error(`Invalid workspace ID format: ${wsId}`);
588→  }
589→
590→  return wsId;
591→}
592→
593→// ---------------------------------------------------------------------------
594→// LLM helper: load workspace skip optimization setting
595→// ---------------------------------------------------------------------------
596→
597→async function loadWorkspaceSkipSetting(
598→  surreal: Surreal,
599→  workspaceRecord: RecordId<"workspace", string>,
600→): Promise<boolean | undefined> {
601→  const [rows] = await surreal.query<[Array<{ settings?: { observer_skip_deterministic?: boolean } }>]>(
602→    `SELECT settings FROM $ws;`,
603→    { ws: workspaceRecord },
604→  );
605→
606→  return rows?.[0]?.settings?.observer_skip_deterministic;
607→}
608→
609→// ---------------------------------------------------------------------------
610→// LLM helper: load completed tasks for decision verification
611→// ---------------------------------------------------------------------------
612→
613→async function queryCompletedTasksForDecision(
614→  surreal: Surreal,
615→  workspaceRecord: RecordId<"workspace", string>,
616→): Promise<Array<{ id: RecordId<"task">; title: string; description?: string }>> {
617→  const [rows] = await surreal.query<[Array<{
618→    id: RecordId<"task">;
619→    title: string;
620→    description?: string;
621→  }>]>(
622→    `SELECT id, title, description FROM task
623→     WHERE workspace = $ws AND status IN ["completed", "done"]
624→     ORDER BY updated_at DESC
625→     LIMIT 20;`,
626→    { ws: workspaceRecord },
627→  );
628→  return rows ?? [];
629→}
630→
631→// ---------------------------------------------------------------------------
632→// LLM helper: load entities linked to an observation via observes edges
633→// ---------------------------------------------------------------------------
634→
635→async function loadObservationLinkedEntities(
636→  surreal: Surreal,
637→  observationId: string,
638→): Promise<Array<{ table: string; id: string; title: string; description?: string }>> {
639→  const observationRecord = new RecordId("observation", observationId);
640→
641→  const [rows] = await surreal.query<[Array<{
642→    out: RecordId;
643→  }>]>(
644→    `SELECT out FROM observes WHERE in = $obs;`,
645→    { obs: observationRecord },
646→  );
647→
648→  if (!rows || rows.length === 0) return [];
649→
650→  const entities: Array<{ table: string; id: string; title: string; description?: string }> = [];
651→
652→  for (const row of rows) {
653→    const targetTable = row.out.table.name;
654→    const targetId = row.out.id as string;
655→    const targetRecord = new RecordId(targetTable, targetId);
656→
657→    const [details] = await surreal.query<[Array<{
658→      title?: string;
659→      summary?: string;
660→      text?: string;
661→      description?: string;
662→    }>]>(
663→      `SELECT title, summary, text, description FROM $record;`,
664→      { record: targetRecord },
665→    );
666→
667→    const detail = details?.[0];
668→    entities.push({
669→      table: targetTable,
670→      id: targetId,
671→      title: detail?.title ?? detail?.summary ?? detail?.text ?? "Unknown",
672→      description: detail?.description,
673→    });
674→  }
675→
676→  return entities;
677→}
