100→    expectedSeverity: "conflict",
101→    expectedReasoningAnchors: ["parameterized", "concatenation"],
102→    expectedFacts: "The task builds SQL queries via string concatenation, which contradicts the decision requiring parameterized statements and forbidding string concatenation in SQL.",
103→  },
104→  {
105→    id: "format-contradiction-xml",
