149→    expectedSeverity: "info",
150→    expectedReasoningAnchors: ["rate limiting", "in_progress"],
151→    expectedFacts: "The PM observation correctly identifies that a rate limiting task has been in progress for an extended period with no linked commits, and the related decision is still provisional.",
152→  },
