167→// ---------------------------------------------------------------------------
168→// Task runner
169→// ---------------------------------------------------------------------------
170→
171→async function runObserverLlmCase(testCase: ObserverLlmTestCase): Promise<ObserverLlmEvalOutput> {
172→  try {
173→    if (testCase.evalType === "verification") {
174→      return await runVerificationCase(testCase);
175→    }
176→    return await runPeerReviewCase(testCase);
177→  } catch (error) {
178→    return {
179→      caseId: testCase.id,
180→      verdict: "",
181→      reasoning: "",
182→      severity: "",
183→      evidenceRefs: [],
184→      success: false,
185→      error: error instanceof Error ? error.message : String(error),
186→    };
187→  }
188→}
189→
190→async function runVerificationCase(testCase: ObserverLlmTestCase): Promise<ObserverLlmEvalOutput> {
191→  const taskRecord = seedResult.tasks.get(testCase.seedCaseKey);
192→  if (!taskRecord) {
193→    throw new Error(`No seeded task for case key: ${testCase.seedCaseKey}`);
194→  }
195→
196→  const taskId = taskRecord.id as string;
197→
198→  // Build entity context (loads related decisions from graph)
199→  const context = await buildEntityContext(
200→    runtime.surreal,
201→    seedResult.workspaceRecord,
202→    "task",
203→    taskId,
204→  );
205→
206→  // Provide a minimal deterministic result for the LLM to enhance
207→  const deterministicResult = {
208→    verdict: "inconclusive" as const,
209→    severity: "info" as const,
210→    verified: false,
211→    text: "Deterministic check: no external signals available.",
212→  };
213→
214→  const llmVerdict = await generateVerificationVerdict(observerModel, context, deterministicResult);
215→  const finalVerdict = applyLlmVerdict(deterministicResult, llmVerdict);
216→
217→  return {
218→    caseId: testCase.id,
219→    verdict: finalVerdict.verdict,
220→    confidence: finalVerdict.confidence,
221→    reasoning: finalVerdict.text,
222→    severity: finalVerdict.severity,
223→    evidenceRefs: finalVerdict.evidenceRefs ?? [],
224→    success: true,
225→  };
226→}
227→
228→async function runPeerReviewCase(testCase: ObserverLlmTestCase): Promise<ObserverLlmEvalOutput> {
229→  const obsRecord = seedResult.observations.get(testCase.seedCaseKey);
230→  if (!obsRecord) {
231→    throw new Error(`No seeded observation for case key: ${testCase.seedCaseKey}`);
232→  }
233→
234→  const obsId = obsRecord.id as string;
235→
236→  // Load the observation details
237→  const [obsRows] = await runtime.surreal.query<[Array<{
238→    text: string;
239→    severity: string;
240→    source_agent: string;
241→  }>]>(
242→    `SELECT text, severity, source_agent FROM $obs;`,
243→    { obs: new RecordId("observation", obsId) },
244→  );
245→  const obs = obsRows?.[0];
246→  if (!obs) throw new Error(`Observation not found: ${obsId}`);
247→
248→  // Load linked entities via observes edges
249→  const [edgeRows] = await runtime.surreal.query<[Array<{ out: RecordId }>]>(
250→    `SELECT out FROM observes WHERE in = $obs;`,
251→    { obs: new RecordId("observation", obsId) },
252→  );
253→
254→  const linkedEntities: Array<{ table: string; id: string; title: string; description?: string }> = [];
255→  for (const row of edgeRows ?? []) {
256→    const targetTable = row.out.table.name;
257→    const targetId = row.out.id as string;
258→    const [details] = await runtime.surreal.query<[Array<{
259→      title?: string; summary?: string; text?: string; description?: string;
260→    }>]>(
261→      `SELECT title, summary, text, description FROM $record;`,
262→      { record: new RecordId(targetTable, targetId) },
263→    );
264→    const d = details?.[0];
265→    linkedEntities.push({
266→      table: targetTable,
267→      id: targetId,
268→      title: d?.title ?? d?.summary ?? d?.text ?? "Unknown",
269→      description: d?.description,
270→    });
271→  }
272→
273→  const llmVerdict = await generatePeerReviewVerdict(
274→    observerModel,
275→    obs.text,
276→    obs.severity,
277→    obs.source_agent,
278→    linkedEntities,
279→  );
280→
281→  if (!llmVerdict) {
