  1→import { RecordId, type Surreal } from "surrealdb";
  2→import { createDeterministicIdGenerator } from "./eval-test-kit";
  3→
  4→export type ObserverLlmSeedResult = {
  5→  workspaceRecord: RecordId<"workspace", string>;
  6→  projectRecord: RecordId<"project", string>;
  7→  /** Decisions seeded in the project, keyed by case ID */
  8→  decisions: Map<string, RecordId<"decision", string>>;
  9→  /** Tasks seeded in the project, keyed by case ID */
 10→  tasks: Map<string, RecordId<"task", string>>;
 11→  /** Observations seeded by non-observer agents, keyed by case ID */
 12→  observations: Map<string, RecordId<"observation", string>>;
 13→};
 14→
 15→export async function seedObserverLlmTestData(surreal: Surreal): Promise<ObserverLlmSeedResult> {
 16→  const nextId = createDeterministicIdGenerator("observer-llm-eval");
 17→  const now = new Date();
 18→  const oneMonthAgo = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
 19→  const twoWeeksAgo = new Date(now.getTime() - 15 * 24 * 60 * 60 * 1000);
 20→
 21→  // Workspace
 22→  const workspaceRecord = new RecordId("workspace", nextId()) as RecordId<"workspace", string>;
 23→  await surreal.create(workspaceRecord).content({
 24→    name: "Observer LLM Eval Workspace",
 25→    status: "active",
 26→    onboarding_complete: true,
 27→    onboarding_turn_count: 5,
 28→    onboarding_summary_pending: false,
 29→    onboarding_started_at: oneMonthAgo,
 30→    created_at: oneMonthAgo,
 31→    updated_at: now,
 32→  });
 33→
 34→  // Owner identity (member_of requires identity, not person)
 35→  const ownerRecord = new RecordId("identity", nextId());
 36→  await surreal.create(ownerRecord).content({
 37→    name: "Eval Owner",
 38→    type: "human",
 39→    workspace: workspaceRecord,
 40→    identity_status: "active",
 41→    created_at: oneMonthAgo,
 42→  });
 43→  await surreal.query(
 44→    `RELATE $identity->member_of->$workspace SET added_at = $added_at;`,
 45→    { identity: ownerRecord, workspace: workspaceRecord, added_at: oneMonthAgo },
 46→  );
 47→
 48→  // Project
 49→  const projectRecord = new RecordId("project", nextId()) as RecordId<"project", string>;
 50→  await surreal.create(projectRecord).content({
 51→    name: "Platform Modernization",
 52→    status: "active",
 53→    workspace: workspaceRecord,
 54→    created_at: oneMonthAgo,
 55→    updated_at: now,
 56→  });
 57→  await surreal
 58→    .relate(workspaceRecord, new RecordId("has_project", nextId()), projectRecord, {
 59→      added_at: oneMonthAgo,
 60→    })
 61→    .output("after");
 62→
 63→  const decisions = new Map<string, RecordId<"decision", string>>();
 64→  const tasks = new Map<string, RecordId<"task", string>>();
 65→  const observations = new Map<string, RecordId<"observation", string>>();
 66→
 67→  // ---------------------------------------------------------------------------
 68→  // Verification eval cases: decisions + tasks
 69→  // ---------------------------------------------------------------------------
 70→
 71→  // Case: clear-contradiction — Decision says no external deps, task adds Redis + Kafka
 72→  const decNoDeps = new RecordId("decision", nextId()) as RecordId<"decision", string>;
 73→  await surreal.create(decNoDeps).content({
 74→    summary: "Minimize external service dependencies. Prefer in-process alternatives over cloud services. No new external dependencies without explicit approval.",
 75→    rationale: "Reduce operational complexity and failure surface area",
 76→    status: "confirmed",
 77→    workspace: workspaceRecord,
 78→    created_at: oneMonthAgo,
 79→    updated_at: oneMonthAgo,
 80→  });
 81→  await surreal
 82→    .relate(decNoDeps, new RecordId("belongs_to", nextId()), projectRecord, { added_at: oneMonthAgo })
 83→    .output("after");
 84→  decisions.set("clear-contradiction", decNoDeps);
 85→
 86→  const taskRedisKafka = new RecordId("task", nextId()) as RecordId<"task", string>;
 87→  await surreal.create(taskRedisKafka).content({
 88→    title: "Add Redis caching layer and Kafka event stream for session management",
 89→    description: "Integrate Redis for distributed caching and Kafka for async event processing. Both are new external service dependencies requiring infrastructure provisioning.",
 90→    status: "completed",
 91→    workspace: workspaceRecord,
 92→    created_at: twoWeeksAgo,
 93→    updated_at: now,
 94→  });
 95→  await surreal
 96→    .relate(taskRedisKafka, new RecordId("belongs_to", nextId()), projectRecord, { added_at: twoWeeksAgo })
 97→    .output("after");
 98→  tasks.set("clear-contradiction", taskRedisKafka);
 99→
100→  // Case: clear-match — Decision says use TypeScript, task uses TypeScript
101→  const decTypescript = new RecordId("decision", nextId()) as RecordId<"decision", string>;
102→  await surreal.create(decTypescript).content({
103→    summary: "Use TypeScript for all backend services. No plain JavaScript files in production code.",
104→    rationale: "Type safety and maintainability across the codebase",
105→    status: "confirmed",
106→    workspace: workspaceRecord,
107→    created_at: oneMonthAgo,
108→    updated_at: oneMonthAgo,
109→  });
110→  await surreal
111→    .relate(decTypescript, new RecordId("belongs_to", nextId()), projectRecord, { added_at: oneMonthAgo })
112→    .output("after");
113→  decisions.set("clear-match", decTypescript);
114→
115→  const taskTsMiddleware = new RecordId("task", nextId()) as RecordId<"task", string>;
116→  await surreal.create(taskTsMiddleware).content({
117→    title: "Implement authentication middleware in TypeScript",
118→    description: "Build JWT authentication middleware using TypeScript with strict type checking and comprehensive test coverage.",
119→    status: "completed",
120→    workspace: workspaceRecord,
121→    created_at: twoWeeksAgo,
122→    updated_at: now,
123→  });
124→  await surreal
125→    .relate(taskTsMiddleware, new RecordId("belongs_to", nextId()), projectRecord, { added_at: twoWeeksAgo })
126→    .output("after");
127→  tasks.set("clear-match", taskTsMiddleware);
128→
129→  // Case: api-contradiction — Decision says tRPC, task uses REST
130→  const decTrpc = new RecordId("decision", nextId()) as RecordId<"decision", string>;
131→  await surreal.create(decTrpc).content({
132→    summary: "Standardize on tRPC for all new API endpoints. REST and GraphQL are forbidden for new services.",
133→    rationale: "End-to-end type safety and reduced boilerplate",
134→    status: "confirmed",
135→    workspace: workspaceRecord,
136→    created_at: oneMonthAgo,
137→    updated_at: oneMonthAgo,
138→  });
139→  await surreal
140→    .relate(decTrpc, new RecordId("belongs_to", nextId()), projectRecord, { added_at: oneMonthAgo })
141→    .output("after");
142→  decisions.set("api-contradiction", decTrpc);
143→
144→  const taskRestBilling = new RecordId("task", nextId()) as RecordId<"task", string>;
145→  await surreal.create(taskRestBilling).content({
146→    title: "Implement billing API with REST endpoints using Express",
147→    description: "Build a RESTful billing API with Express routes for payment processing, invoice generation, and subscription management. Uses standard REST conventions.",
148→    status: "completed",
149→    workspace: workspaceRecord,
150→    created_at: twoWeeksAgo,
151→    updated_at: now,
152→  });
153→  await surreal
154→    .relate(taskRestBilling, new RecordId("belongs_to", nextId()), projectRecord, { added_at: twoWeeksAgo })
155→    .output("after");
156→  tasks.set("api-contradiction", taskRestBilling);
157→
158→  // Case: ambiguous — Decision is loosely related, task is tangential
159→  const decConvention = new RecordId("decision", nextId()) as RecordId<"decision", string>;
160→  await surreal.create(decConvention).content({
161→    summary: "Prefer convention over configuration for internal tooling",
162→    rationale: "Reduce onboarding friction for new team members",
163→    status: "confirmed",
164→    workspace: workspaceRecord,
165→    created_at: oneMonthAgo,
166→    updated_at: oneMonthAgo,
167→  });
168→  await surreal
169→    .relate(decConvention, new RecordId("belongs_to", nextId()), projectRecord, { added_at: oneMonthAgo })
170→    .output("after");
171→  decisions.set("ambiguous", decConvention);
172→
173→  const taskLinterConfig = new RecordId("task", nextId()) as RecordId<"task", string>;
174→  await surreal.create(taskLinterConfig).content({
175→    title: "Add ESLint configuration file for project-specific rules",
176→    description: "Create .eslintrc with linting rules tailored to the project's coding standards.",
177→    status: "completed",
178→    workspace: workspaceRecord,
179→    created_at: twoWeeksAgo,
180→    updated_at: now,
181→  });
182→  await surreal
183→    .relate(taskLinterConfig, new RecordId("belongs_to", nextId()), projectRecord, { added_at: twoWeeksAgo })
184→    .output("after");
185→  tasks.set("ambiguous", taskLinterConfig);
186→
187→  // Case: security-contradiction — Decision says parameterized queries, task uses string concat
188→  const decParamQueries = new RecordId("decision", nextId()) as RecordId<"decision", string>;
189→  await surreal.create(decParamQueries).content({
190→    summary: "All database queries must use parameterized statements. No string concatenation in SQL queries under any circumstances.",
191→    rationale: "SQL injection prevention and security compliance",
192→    status: "confirmed",
193→    workspace: workspaceRecord,
194→    created_at: oneMonthAgo,
195→    updated_at: oneMonthAgo,
196→  });
197→  await surreal
198→    .relate(decParamQueries, new RecordId("belongs_to", nextId()), projectRecord, { added_at: oneMonthAgo })
199→    .output("after");
200→  decisions.set("security-contradiction", decParamQueries);
201→
202→  const taskDynamicSql = new RecordId("task", nextId()) as RecordId<"task", string>;
203→  await surreal.create(taskDynamicSql).content({
204→    title: "Build admin search with dynamic SQL string construction",
205→    description: "Implement admin search by building SQL queries via string concatenation based on user-provided filter parameters for flexible querying.",
206→    status: "completed",
207→    workspace: workspaceRecord,
208→    created_at: twoWeeksAgo,
209→    updated_at: now,
210→  });
211→  await surreal
212→    .relate(taskDynamicSql, new RecordId("belongs_to", nextId()), projectRecord, { added_at: twoWeeksAgo })
213→    .output("after");
214→  tasks.set("security-contradiction", taskDynamicSql);
215→
216→  // Case: format-contradiction — Decision says JSON only, task outputs XML
217→  const decJsonOnly = new RecordId("decision", nextId()) as RecordId<"decision", string>;
218→  await surreal.create(decJsonOnly).content({
219→    summary: "All API responses must use JSON format exclusively. No XML, HTML, or plain text responses from any endpoint.",
220→    rationale: "Consistent API contract for all consumers",
221→    status: "confirmed",
222→    workspace: workspaceRecord,
223→    created_at: oneMonthAgo,
224→    updated_at: oneMonthAgo,
225→  });
226→  await surreal
227→    .relate(decJsonOnly, new RecordId("belongs_to", nextId()), projectRecord, { added_at: oneMonthAgo })
228→    .output("after");
229→  decisions.set("format-contradiction", decJsonOnly);
230→
231→  const taskXmlExport = new RecordId("task", nextId()) as RecordId<"task", string>;
232→  await surreal.create(taskXmlExport).content({
233→    title: "Implement XML export endpoint for legacy ERP integration",
234→    description: "Build an endpoint that returns XML-formatted data for the legacy ERP system. The ERP only accepts XML payloads.",
235→    status: "completed",
