 39→// ---------------------------------------------------------------------------
 40→// Shared observation persistence
 41→// ---------------------------------------------------------------------------
 42→
 43→async function persistVerificationObservation(
 44→  surreal: Surreal,
 45→  workspaceRecord: RecordId<"workspace", string>,
 46→  relatedRecord: RecordId,
 47→  verificationResult: VerificationResult,
 48→  defaultSource = "none",
 49→  additionalRelatedRecords?: ObserveTargetRecord[],
 50→): Promise<void> {
 51→  const now = new Date();
 52→
 53→  // Convert evidence_refs strings to RecordId objects
 54→  const evidenceRefRecords: RecordId[] = [];
 55→  for (const ref of verificationResult.evidenceRefs ?? []) {
 56→    const parsed = parseEntityRef(ref);
 57→    if (parsed) evidenceRefRecords.push(new RecordId(parsed.table, parsed.id));
 58→  }
 59→
 60→  const observationRecord = await createObservation({
 61→    surreal,
 62→    workspaceRecord,
 63→    text: verificationResult.text,
 64→    severity: verificationResult.severity,
 65→    sourceAgent: "observer_agent",
 66→    observationType: verificationResult.observationType ?? "validation",
 67→    now,
 68→    relatedRecord: relatedRecord as ObserveTargetRecord,
 69→    relatedRecords: additionalRelatedRecords,
 70→    confidence: verificationResult.confidence,
 71→    evidenceRefs: evidenceRefRecords.length > 0 ? evidenceRefRecords : undefined,
 72→  });
 73→
 74→  await surreal.query(
 75→    `UPDATE $obs SET verified = $verified, source = $source;`,
 76→    {
 77→      obs: observationRecord,
 78→      verified: verificationResult.verified,
 79→      source: verificationResult.source ?? defaultSource,
 80→    },
 81→  );
 82→}
