 88→export function createObserverRouteHandler(deps: ServerDependencies) {
 89→  return async (table: string, id: string, request: Request): Promise<Response> => {
 90→    if (!SUPPORTED_TABLES.has(table)) {
 91→      return jsonResponse({ error: "unsupported_table", table }, 400);
 92→    }
 93→
 94→    const supportedTable = table as SupportedTable;
 95→
 96→    try {
 97→      // Parse the EVENT body (the record itself, posted by SurrealDB EVENT)
 98→      const body = await request.json().catch(() => undefined);
 99→
100→      logInfo("observer.event.received", "Observer event received", {
101→        table: supportedTable,
102→        id,
103→      });
104→
105→      // Dispatch to the appropriate verification pipeline
106→      switch (supportedTable) {
107→        case "task":
108→          await handleTaskVerification(deps, id, body);
109→          break;
110→
111→        case "intent":
112→          await handleIntentVerification(deps, id, body);
113→          break;
114→
115→        case "git_commit":
116→          await handleCommitVerification(deps, id, body);
117→          break;
118→
119→        case "decision":
120→          await handleDecisionVerification(deps, id, body);
121→          break;
122→
123→        case "observation":
124→          await handleObservationPeerReview(deps, id, body);
125→          break;
126→      }
127→
128→      return jsonResponse({ status: "ok" }, 200);
129→    } catch (error) {
130→      logError("observer.event.error", "Observer event processing failed", error);
131→      // Return 200 to prevent SurrealDB EVENT retries for non-transient errors
132→      return jsonResponse({ status: "error", message: "processing failed" }, 200);
133→    }
134→  };
135→}
