545→const UUID_PATTERN = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
546→
547→async function resolveWorkspaceId(
548→  surreal: Surreal,
549→  table: string,
550→  id: string,
551→  body?: Record<string, unknown>,
552→): Promise<string | undefined> {
553→  // Try body first (SurrealDB EVENT passes the full record)
554→  let wsId: string | undefined;
555→
556→  if (body?.workspace) {
557→    const ws = body.workspace;
558→    // Could be a RecordId-like object or a string
