  1→/**
  2→ * Observer HTTP route: POST /api/observe/:table/:id
  3→ *
  4→ * Effect shell that wires the verification pipeline to SurrealDB.
  5→ * Called by SurrealDB EVENTs when entity state transitions occur.
  6→ *
  7→ * Pipeline: receiveEvent -> gatherSignals -> compareClaimVsReality -> persistObservation
  8→ */
  9→
 10→import { RecordId, type Surreal } from "surrealdb";
 11→import type { LanguageModel } from "ai";
 12→import { jsonResponse } from "../http/response";
 13→import { logError, logInfo } from "../http/observability";
 14→import { createObservation, type ObserveTargetRecord } from "../observation/queries";
 15→import { checkCiStatus } from "./external-signals";
 16→import { compareIntentCompletion, compareCommitStatus, compareDecisionConfirmation, compareObservationPeerReview, shouldSkipLlm, applyLlmVerdict } from "./verification-pipeline";
 17→import type { IntentSignals, DecisionSignals, ObservationPeerReviewSignals, VerificationResult } from "./verification-pipeline";
 18→import type { ServerDependencies } from "../runtime/types";
 19→import { runObserverAgent } from "../agents/observer/agent";
 20→import { runGraphScan } from "./graph-scan";
 21→import { buildEntityContext } from "./context-loader";
 22→import { generateVerificationVerdict, generatePeerReviewVerdict } from "./llm-reasoning";
 23→import { parseEntityRef } from "./evidence-validator";
 24→
 25→// ---------------------------------------------------------------------------
 26→// Types
 27→// ---------------------------------------------------------------------------
 28→
 29→type SupportedTable = "task" | "intent" | "git_commit" | "decision" | "observation";
 30→
 31→const SUPPORTED_TABLES = new Set<string>([
 32→  "task",
 33→  "intent",
 34→  "git_commit",
 35→  "decision",
 36→  "observation",
 37→]);
 38→
 39→// ---------------------------------------------------------------------------
 40→// Shared observation persistence
 41→// ---------------------------------------------------------------------------
 42→
 43→async function persistVerificationObservation(
 44→  surreal: Surreal,
 45→  workspaceRecord: RecordId<"workspace", string>,
 46→  relatedRecord: RecordId,
 47→  verificationResult: VerificationResult,
 48→  defaultSource = "none",
 49→  additionalRelatedRecords?: ObserveTargetRecord[],
 50→): Promise<void> {
 51→  const now = new Date();
 52→
 53→  // Convert evidence_refs strings to RecordId objects
 54→  const evidenceRefRecords: RecordId[] = [];
 55→  for (const ref of verificationResult.evidenceRefs ?? []) {
 56→    const parsed = parseEntityRef(ref);
 57→    if (parsed) evidenceRefRecords.push(new RecordId(parsed.table, parsed.id));
 58→  }
 59→
 60→  const observationRecord = await createObservation({
 61→    surreal,
 62→    workspaceRecord,
 63→    text: verificationResult.text,
 64→    severity: verificationResult.severity,
 65→    sourceAgent: "observer_agent",
 66→    observationType: verificationResult.observationType ?? "validation",
 67→    now,
 68→    relatedRecord: relatedRecord as ObserveTargetRecord,
 69→    relatedRecords: additionalRelatedRecords,
 70→    confidence: verificationResult.confidence,
 71→    evidenceRefs: evidenceRefRecords.length > 0 ? evidenceRefRecords : undefined,
 72→  });
 73→
 74→  await surreal.query(
 75→    `UPDATE $obs SET verified = $verified, source = $source;`,
 76→    {
 77→      obs: observationRecord,
 78→      verified: verificationResult.verified,
 79→      source: verificationResult.source ?? defaultSource,
 80→    },
 81→  );
 82→}
 83→
 84→// ---------------------------------------------------------------------------
 85→// Route handler factory
 86→// ---------------------------------------------------------------------------
 87→
 88→export function createObserverRouteHandler(deps: ServerDependencies) {
 89→  return async (table: string, id: string, request: Request): Promise<Response> => {
 90→    if (!SUPPORTED_TABLES.has(table)) {
 91→      return jsonResponse({ error: "unsupported_table", table }, 400);
 92→    }
 93→
 94→    const supportedTable = table as SupportedTable;
 95→
 96→    try {
 97→      // Parse the EVENT body (the record itself, posted by SurrealDB EVENT)
 98→      const body = await request.json().catch(() => undefined);
 99→
100→      logInfo("observer.event.received", "Observer event received", {
101→        table: supportedTable,
102→        id,
103→      });
104→
105→      // Dispatch to the appropriate verification pipeline
106→      switch (supportedTable) {
107→        case "task":
108→          await handleTaskVerification(deps, id, body);
109→          break;
110→
111→        case "intent":
112→          await handleIntentVerification(deps, id, body);
113→          break;
114→
115→        case "git_commit":
116→          await handleCommitVerification(deps, id, body);
117→          break;
118→
119→        case "decision":
120→          await handleDecisionVerification(deps, id, body);
121→          break;
122→
123→        case "observation":
124→          await handleObservationPeerReview(deps, id, body);
125→          break;
126→      }
127→
128→      return jsonResponse({ status: "ok" }, 200);
129→    } catch (error) {
130→      logError("observer.event.error", "Observer event processing failed", error);
131→      // Return 200 to prevent SurrealDB EVENT retries for non-transient errors
132→      return jsonResponse({ status: "error", message: "processing failed" }, 200);
133→    }
134→  };
135→}
136→
137→// ---------------------------------------------------------------------------
138→// Task verification pipeline (effect shell)
139→// ---------------------------------------------------------------------------
140→
141→async function handleTaskVerification(
142→  deps: ServerDependencies,
143→  taskId: string,
144→  body?: Record<string, unknown>,
145→): Promise<void> {
146→  const { surreal } = deps;
147→
148→  // Resolve workspace from the task record body or by querying
149→  const workspaceId = await resolveWorkspaceId(surreal, "task", taskId, body);
150→  if (!workspaceId) {
151→    logError("observer.task.no_workspace", "Cannot determine workspace for task", { taskId });
152→    return;
153→  }
154→
155→  const workspaceRecord = new RecordId("workspace", workspaceId);
156→
157→  // Run deterministic verification via observer agent
158→  const agentOutput = await runObserverAgent({
159→    surreal,
160→    workspaceRecord,
161→    entityTable: "task",
162→    entityId: taskId,
163→    entityBody: body,
164→  });
165→
166→  // LLM reasoning path (when observer model is configured)
167→  if (deps.observerModel) {
168→    const taskRecord = new RecordId("task", taskId);
169→
170→    // Load workspace settings for skip optimization
171→    const skipDeterministic = await loadWorkspaceSkipSetting(surreal, workspaceRecord);
172→
173→    // Build deterministic result from agent output for skip check
174→    const deterministicResult: VerificationResult = {
175→      verdict: agentOutput.verdict,
176→      severity: agentOutput.verdict === "mismatch" ? "conflict" : "info",
177→      verified: agentOutput.verdict === "match",
178→      text: agentOutput.evidence.join("; ") || "Deterministic verification complete",
179→    };
180→
181→    if (shouldSkipLlm(deterministicResult, skipDeterministic)) {
182→      logInfo("observer.llm.skip", "LLM skipped: deterministic match + CI passing", { taskId });
183→    } else {
184→      const context = await buildEntityContext(surreal, workspaceRecord, "task", taskId, body);
185→      const llmVerdict = await generateVerificationVerdict(
186→        deps.observerModel as LanguageModel,
187→        context,
188→        deterministicResult,
189→      );
190→
191→      const finalVerdict = applyLlmVerdict(deterministicResult, llmVerdict);
192→
193→      // Build related records: task + any contradicted decisions
194→      const additionalRecords: ObserveTargetRecord[] = [];
195→      if (llmVerdict?.verdict === "mismatch" && llmVerdict.evidence_refs) {
196→        for (const ref of llmVerdict.evidence_refs) {
197→          const parsed = parseEntityRef(ref);
198→          if (parsed && parsed.table === "decision") {
199→            additionalRecords.push(new RecordId("decision", parsed.id) as ObserveTargetRecord);
200→          }
201→        }
202→      }
203→
204→      await persistVerificationObservation(
205→        surreal, workspaceRecord, taskRecord, finalVerdict, "none", additionalRecords,
206→      );
207→    }
208→  }
209→
210→  logInfo("observer.task.verified", "Task verification complete", {
211→    taskId,
212→    verdict: agentOutput.verdict,
213→    observationsCreated: agentOutput.observations_created,
214→    evidence: agentOutput.evidence,
215→  });
216→}
217→
218→// ---------------------------------------------------------------------------
219→// Intent verification pipeline (effect shell)
220→// ---------------------------------------------------------------------------
221→
222→async function handleIntentVerification(
223→  deps: ServerDependencies,
224→  intentId: string,
225→  body?: Record<string, unknown>,
226→): Promise<void> {
227→  const { surreal } = deps;
228→
229→  const workspaceId = await resolveWorkspaceId(surreal, "intent", intentId, body);
230→  if (!workspaceId) {
231→    logError("observer.intent.no_workspace", "Cannot determine workspace for intent", { intentId });
232→    return;
233→  }
234→
235→  const workspaceRecord = new RecordId("workspace", workspaceId);
236→  const intentRecord = new RecordId("intent", intentId);
237→
238→  // Gather intent signals: status and trace presence
239→  const intentSignals = await gatherIntentSignals(surreal, intentId, body);
240→  const verificationResult = compareIntentCompletion(intentSignals);
241→
242→  await persistVerificationObservation(surreal, workspaceRecord, intentRecord, verificationResult);
243→
244→  logInfo("observer.intent.verified", "Intent verification complete", {
245→    intentId,
246→    verdict: verificationResult.verdict,
247→    severity: verificationResult.severity,
248→    verified: verificationResult.verified,
249→  });
250→}
251→
252→async function gatherIntentSignals(
253→  surreal: Surreal,
254→  intentId: string,
255→  body?: Record<string, unknown>,
256→): Promise<IntentSignals> {
257→  // Prefer body (from EVENT payload) for status and goal
258→  const status = (body?.status as string) ?? "unknown";
259→  const goal = (body?.goal as string) ?? "Unknown intent";
260→
261→  // Check if a trace exists
262→  const intentRecord = new RecordId("intent", intentId);
263→  const [traceRows] = await surreal.query<[Array<{ trace_id?: RecordId }>]>(
264→    `SELECT trace_id FROM $intent;`,
265→    { intent: intentRecord },
266→  );
267→
268→  const hasTrace = !!traceRows?.[0]?.trace_id;
269→
270→  return { status, goal, hasTrace };
271→}
272→
273→// ---------------------------------------------------------------------------
274→// Commit verification pipeline (effect shell)
275→// ---------------------------------------------------------------------------
276→
277→async function handleCommitVerification(
278→  deps: ServerDependencies,
279→  commitId: string,
280→  body?: Record<string, unknown>,
281→): Promise<void> {
282→  const { surreal } = deps;
283→
284→  const workspaceId = await resolveWorkspaceId(surreal, "git_commit", commitId, body);
285→  if (!workspaceId) {
286→    logError("observer.commit.no_workspace", "Cannot determine workspace for commit", { commitId });
287→    return;
288→  }
289→
290→  const workspaceRecord = new RecordId("workspace", workspaceId);
291→  const commitRecord = new RecordId("git_commit", commitId);
292→
293→  // Gather CI signals for this commit
294→  const sha = (body?.sha as string) ?? "";
295→  const repository = (body?.repository as string) ?? "";
296→
297→  const signal = await checkCiStatus({
298→    id: commitRecord,
299→    sha,
300→    repository,
301→  });
302→
303→  const signalsResult = {
304→    signals: [signal],
305→    hasCommits: true,
306→  };
307→
308→  const verificationResult = compareCommitStatus(signalsResult);
309→
310→  await persistVerificationObservation(surreal, workspaceRecord, commitRecord, verificationResult);
311→
312→  logInfo("observer.commit.verified", "Commit verification complete", {
313→    commitId,
314→    verdict: verificationResult.verdict,
315→    severity: verificationResult.severity,
316→    verified: verificationResult.verified,
317→  });
318→}
319→
320→// ---------------------------------------------------------------------------
321→// Decision verification pipeline (effect shell)
322→// ---------------------------------------------------------------------------
323→
324→async function handleDecisionVerification(
325→  deps: ServerDependencies,
326→  decisionId: string,
327→  body?: Record<string, unknown>,
328→): Promise<void> {
329→  const { surreal } = deps;
330→
331→  // Skip initial CREATE events -- only verify actual status transitions (UPDATEs).
332→  if (!body?.updated_at) {
333→    logInfo("observer.decision.skipped_create", "Skipping decision CREATE event (not a status transition)", { decisionId });
334→    return;
335→  }
336→
337→  const workspaceId = await resolveWorkspaceId(surreal, "decision", decisionId, body);
338→  if (!workspaceId) {
339→    logError("observer.decision.no_workspace", "Cannot determine workspace for decision", { decisionId });
340→    return;
341→  }
342→
343→  const workspaceRecord = new RecordId("workspace", workspaceId);
344→  const decisionRecord = new RecordId("decision", decisionId);
345→
346→  // Gather decision signals: status, summary, and completed task count
347→  const decisionSignals = await gatherDecisionSignals(surreal, workspaceRecord, body);
348→  const deterministicResult = compareDecisionConfirmation(decisionSignals);
349→
350→  await persistVerificationObservation(surreal, workspaceRecord, decisionRecord, deterministicResult);
351→
352→  // LLM reasoning: when decision confirmed, check completed tasks against it
353→  if (deps.observerModel && body?.status === "confirmed" && decisionSignals.completedTaskCount > 0) {
354→    const completedTasks = await queryCompletedTasksForDecision(surreal, workspaceRecord);
355→
356→    for (const task of completedTasks) {
357→      const taskId = task.id.id as string;
358→      const taskBody = { title: task.title, description: task.description, status: "completed" };
359→      const context = await buildEntityContext(surreal, workspaceRecord, "task", taskId, taskBody);
360→      const llmVerdict = await generateVerificationVerdict(
361→        deps.observerModel as LanguageModel,
362→        context,
363→        deterministicResult,
364→      );
365→
366→      if (!llmVerdict || llmVerdict.verdict !== "mismatch") continue;
367→
368→      const finalVerdict = applyLlmVerdict(deterministicResult, llmVerdict);
369→      const taskRecord = new RecordId("task", taskId) as ObserveTargetRecord;
370→
371→      await persistVerificationObservation(
372→        surreal, workspaceRecord, decisionRecord, finalVerdict, "none", [taskRecord],
373→      );
374→    }
375→  }
376→
377→  logInfo("observer.decision.verified", "Decision verification complete", {
378→    decisionId,
379→    verdict: deterministicResult.verdict,
380→    severity: deterministicResult.severity,
381→    verified: deterministicResult.verified,
382→  });
383→}
384→
385→// ---------------------------------------------------------------------------
386→// Observation peer review pipeline (effect shell)
387→// ---------------------------------------------------------------------------
388→
389→async function handleObservationPeerReview(
390→  deps: ServerDependencies,
391→  observationId: string,
392→  body?: Record<string, unknown>,
393→): Promise<void> {
394→  const { surreal } = deps;
395→
396→  const workspaceId = await resolveWorkspaceId(surreal, "observation", observationId, body);
397→  if (!workspaceId) {
398→    logError("observer.observation.no_workspace", "Cannot determine workspace for observation", { observationId });
399→    return;
400→  }
401→
402→  const workspaceRecord = new RecordId("workspace", workspaceId);
403→  const originalObservationRecord = new RecordId("observation", observationId);
404→
405→  // Gather peer review signals from the original observation and workspace context
406→  const peerReviewSignals = await gatherObservationPeerReviewSignals(surreal, workspaceRecord, body);
407→  const deterministicResult = compareObservationPeerReview(peerReviewSignals);
408→
409→  // LLM peer review: evaluate evidence quality when model configured and observation has linked entities
410→  if (deps.observerModel) {
411→    const linkedEntities = await loadObservationLinkedEntities(surreal, observationId);
412→
413→    if (linkedEntities.length > 0) {
414→      const originalText = (body?.text as string) ?? "Unknown observation";
415→      const originalSeverity = (body?.severity as string) ?? "info";
416→      const sourceAgent = (body?.source_agent as string) ?? "unknown_agent";
417→
418→      const llmVerdict = await generatePeerReviewVerdict(
419→        deps.observerModel as LanguageModel,
420→        originalText,
421→        originalSeverity,
422→        sourceAgent,
423→        linkedEntities,
424→      );
425→
426→      if (llmVerdict) {
427→        // Map peer review verdict to verification result
428→        const severity = llmVerdict.verdict === "unsupported" ? "warning" as const
429→          : llmVerdict.verdict === "questionable" ? "info" as const
430→          : "info" as const;
431→
432→        const reviewResult: VerificationResult = {
433→          verdict: llmVerdict.verdict === "sound" ? "match" : llmVerdict.verdict === "unsupported" ? "mismatch" : "inconclusive",
434→          severity,
435→          verified: llmVerdict.verdict === "sound",
436→          text: llmVerdict.reasoning,
437→          source: "llm",
438→          confidence: llmVerdict.confidence,
439→          observationType: "validation",
440→        };
441→
442→        await persistVerificationObservation(
443→          surreal, workspaceRecord, originalObservationRecord, reviewResult, "llm",
444→        );
445→
446→        logInfo("observer.observation.llm_peer_reviewed", "LLM peer review complete", {
447→          observationId,
448→          verdict: llmVerdict.verdict,
449→          confidence: llmVerdict.confidence,
450→        });
451→        return;
452→      }
453→      // LLM failed — fall through to deterministic
454→      logInfo("observer.llm.fallback", "LLM peer review failed, using deterministic", { observationId });
455→    } else {
456→      logInfo("observer.llm.skip", "LLM peer review skipped: no linked entities", { observationId });
457→    }
458→  }
459→
460→  // Deterministic fallback
461→  await persistVerificationObservation(surreal, workspaceRecord, originalObservationRecord, deterministicResult, "peer_review");
462→
463→  logInfo("observer.observation.peer_reviewed", "Observation peer review complete", {
464→    observationId,
465→    verdict: deterministicResult.verdict,
466→    severity: deterministicResult.severity,
467→  });
468→}
469→
470→async function gatherObservationPeerReviewSignals(
471→  surreal: Surreal,
472→  workspaceRecord: RecordId<"workspace", string>,
473→  body?: Record<string, unknown>,
474→): Promise<ObservationPeerReviewSignals> {
475→  const originalText = (body?.text as string) ?? "Unknown observation";
476→  const originalSeverity = ((body?.severity as string) ?? "info") as "info" | "warning" | "conflict";
477→  const sourceAgent = (body?.source_agent as string) ?? "unknown_agent";
478→
479→  // Count tasks and decisions in the workspace for cross-checking context
480→  const [taskRows] = await surreal.query<[Array<{ count: number }>]>(
481→    `SELECT count() AS count FROM task WHERE workspace = $ws GROUP ALL;`,
482→    { ws: workspaceRecord },
483→  );
484→
485→  const [decisionRows] = await surreal.query<[Array<{ count: number }>]>(
486→    `SELECT count() AS count FROM decision WHERE workspace = $ws GROUP ALL;`,
487→    { ws: workspaceRecord },
488→  );
489→
490→  return {
491→    originalText,
492→    originalSeverity,
493→    sourceAgent,
494→    relatedTaskCount: taskRows?.[0]?.count ?? 0,
495→    relatedDecisionCount: decisionRows?.[0]?.count ?? 0,
496→  };
497→}
498→
499→async function gatherDecisionSignals(
500→  surreal: Surreal,
501→  workspaceRecord: RecordId<"workspace", string>,
502→  body?: Record<string, unknown>,
503→): Promise<DecisionSignals> {
504→  const status = (body?.status as string) ?? "unknown";
505→  const summary = (body?.summary as string) ?? "Unknown decision";
506→
507→  // Count completed tasks in the workspace
508→  const [taskRows] = await surreal.query<[Array<{ count: number }>]>(
509→    `SELECT count() AS count FROM task WHERE workspace = $ws AND (status = "completed" OR status = "done") GROUP ALL;`,
510→    { ws: workspaceRecord },
511→  );
512→
513→  const completedTaskCount = taskRows?.[0]?.count ?? 0;
514→
515→  return { status, summary, completedTaskCount };
516→}
517→
518→// ---------------------------------------------------------------------------
519→// Graph scan route handler factory
520→// ---------------------------------------------------------------------------
521→
522→export function createGraphScanRouteHandler(deps: ServerDependencies) {
523→  return async (workspaceId: string, _request: Request): Promise<Response> => {
524→    try {
525→      logInfo("observer.scan.started", "Graph scan triggered", { workspaceId });
526→
527→      const workspaceRecord = new RecordId("workspace", workspaceId);
528→      const result = await runGraphScan(deps.surreal, workspaceRecord, deps.observerModel as LanguageModel | undefined);
529→
530→      return jsonResponse({
531→        status: "ok",
532→        ...result,
533→      }, 200);
534→    } catch (error) {
535→      logError("observer.scan.error", "Graph scan failed", error);
536→      return jsonResponse({ status: "error", message: "scan failed" }, 500);
537→    }
538→  };
539→}
540→
541→// ---------------------------------------------------------------------------
542→// Workspace resolution
543→// ---------------------------------------------------------------------------
544→
545→const UUID_PATTERN = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
546→
547→async function resolveWorkspaceId(
548→  surreal: Surreal,
549→  table: string,
550→  id: string,
551→  body?: Record<string, unknown>,
552→): Promise<string | undefined> {
553→  // Try body first (SurrealDB EVENT passes the full record)
554→  let wsId: string | undefined;
555→
556→  if (body?.workspace) {
557→    const ws = body.workspace;
558→    // Could be a RecordId-like object or a string
559→    if (typeof ws === "string") {
560→      // Handle "workspace:uuid" format and strip backticks
561→      const cleaned = ws.replace(/`/g, "");
562→      wsId = cleaned.includes(":") ? cleaned.split(":")[1] : cleaned;
563→    } else if (typeof ws === "object" && ws !== null) {
564→      const wsObj = ws as { id?: string | { String?: string } };
565→      if (typeof wsObj.id === "string") wsId = wsObj.id.replace(/`/g, "");
566→      else if (wsObj.id && typeof (wsObj.id as { String?: string }).String === "string") {
567→        wsId = (wsObj.id as { String: string }).String.replace(/`/g, "");
568→      }
569→    }
570→  }
571→
572→  // Fallback: query the DB
573→  if (!wsId) {
574→    const record = new RecordId(table, id);
575→    const [rows] = await surreal.query<
576→      [Array<{ workspace: RecordId<"workspace", string> }>]
577→    >(
578→      `SELECT workspace FROM $record;`,
579→      { record },
580→    );
581→
582→    const wsRecord = rows?.[0]?.workspace;
583→    wsId = wsRecord ? (wsRecord.id as string) : undefined;
584→  }
585→
586→  if (wsId && !UUID_PATTERN.test(wsId)) {
587→    throw new Error(`Invalid workspace ID format: ${wsId}`);
588→  }
589→
590→  return wsId;
591→}
592→
593→// ---------------------------------------------------------------------------
594→// LLM helper: load workspace skip optimization setting
595→// ---------------------------------------------------------------------------
596→
597→async function loadWorkspaceSkipSetting(
598→  surreal: Surreal,
599→  workspaceRecord: RecordId<"workspace", string>,
600→): Promise<boolean | undefined> {
601→  const [rows] = await surreal.query<[Array<{ settings?: { observer_skip_deterministic?: boolean } }>]>(
602→    `SELECT settings FROM $ws;`,
603→    { ws: workspaceRecord },
604→  );
605→
606→  return rows?.[0]?.settings?.observer_skip_deterministic;
607→}
608→
609→// ---------------------------------------------------------------------------
610→// LLM helper: load completed tasks for decision verification
611→// ---------------------------------------------------------------------------
612→
613→async function queryCompletedTasksForDecision(
614→  surreal: Surreal,
615→  workspaceRecord: RecordId<"workspace", string>,
616→): Promise<Array<{ id: RecordId<"task">; title: string; description?: string }>> {
617→  const [rows] = await surreal.query<[Array<{
618→    id: RecordId<"task">;
619→    title: string;
620→    description?: string;
621→  }>]>(
622→    `SELECT id, title, description FROM task
623→     WHERE workspace = $ws AND status IN ["completed", "done"]
624→     ORDER BY updated_at DESC
625→     LIMIT 20;`,
626→    { ws: workspaceRecord },
627→  );
628→  return rows ?? [];
629→}
630→
631→// ---------------------------------------------------------------------------
632→// LLM helper: load entities linked to an observation via observes edges
633→// ---------------------------------------------------------------------------
634→
635→async function loadObservationLinkedEntities(
636→  surreal: Surreal,
637→  observationId: string,
638→): Promise<Array<{ table: string; id: string; title: string; description?: string }>> {
639→  const observationRecord = new RecordId("observation", observationId);
640→
641→  const [rows] = await surreal.query<[Array<{
642→    out: RecordId;
643→  }>]>(
644→    `SELECT out FROM observes WHERE in = $obs;`,
645→    { obs: observationRecord },
646→  );
647→
648→  if (!rows || rows.length === 0) return [];
649→
650→  const entities: Array<{ table: string; id: string; title: string; description?: string }> = [];
651→
652→  for (const row of rows) {
653→    const targetTable = row.out.table.name;
654→    const targetId = row.out.id as string;
655→    const targetRecord = new RecordId(targetTable, targetId);
656→
657→    const [details] = await surreal.query<[Array<{
658→      title?: string;
659→      summary?: string;
660→      text?: string;
661→      description?: string;
662→    }>]>(
663→      `SELECT title, summary, text, description FROM $record;`,
664→      { record: targetRecord },
665→    );
666→
667→    const detail = details?.[0];
668→    entities.push({
669→      table: targetTable,
670→      id: targetId,
671→      title: detail?.title ?? detail?.summary ?? detail?.text ?? "Unknown",
672→      description: detail?.description,
673→    });
674→  }
675→
676→  return entities;
677→}
